import sys
input = sys.stdin.readline

def solve(n, m):
    if n > m:
        return 0
    L = m + 1
    y = 0
    greater = False
    for i in range(31, -1, -1):
        nb = (n >> i) & 1
        lb = (L >> i) & 1
        if greater:
            y_bit = nb
        else:
            if nb == lb:
                y_bit = nb
            else:
                y_bit = max(nb, lb)
                if y_bit > lb:
                    greater = True
        y = (y << 1) | y_bit
    return n ^ y

t = int(input())
for _ in range(t):
    n, m = map(int, input().split())
    print(solve(n, m))
